-- Set machine sequence to max id + 1
SELECT setval('machines_id_seq', (SELECT MAX(id) FROM machines));

-- Create initial movement_history records (first installation: from=NULL, to=current location)
INSERT INTO movement_history (machine_id, from_location_id, to_location_id, moved_at, created_at)
SELECT m.id, NULL, m.location_id, m.created_at, m.created_at
FROM machines m
WHERE m.location_id IS NOT NULL;
